     const needsStdinFlag = ['bash', 'sh'].includes(vi.runner);
-    if (needsStdinFlag) {
+    const argsHaveStdinFlag = vi.args?.includes('-s') ?? false;
+    if (needsStdinFlag && !argsHaveStdinFlag) {
       parts.push("'-s'");
     }
